// ============================================================
// AdaptationWorker — Préparer l'appel à l'AdaptationAgent
// ============================================================
// Le queue-service envoie :
//   { queue_name, job_id (BullMQ), attempt, job_id (métier), correlation_id, action }
// Format attendu par AdaptationAgent :
//   { job_id, correlation_id, action: 'ADAPT_CONTENT' }
// ============================================================

const input = $input.first().json.body || $input.first().json;

return [{
  json: {
    tenant_id: input.tenant_id || 1,
    job_id: input.job_id,
    correlation_id: input.correlation_id || '',
    action: 'ADAPT_CONTENT',
    _queue_tenant_id: input.tenant_id,
    _queue_attempt: input.attempt || 1,
  }
}];

// ============================================================
// Analyser résultat de l'AdaptationAgent
// ============================================================
// Si ADAPTED → enqueue dans publication-{canal}
// Si échec → log et fin (BullMQ retry automatiquement si transient)
// ============================================================

const result = $input.first().json;
const prep = $('Préparer appel Adaptation').first().json;
const p = result.payload || result;

const resultStatus = p.result_status || 'UNKNOWN';
const jobId = p.job_id || prep.job_id;
const correlation_id = result.correlation_id || prep.correlation_id;

// Déterminer le canal pour le routage
const channel = (p.channel_name || '').toUpperCase();

let queueTarget = null;
if (resultStatus === 'ADAPTED') {
  if (channel === 'FACEBOOK') queueTarget = 'publication-facebook';
  else if (channel === 'INSTAGRAM') queueTarget = 'publication-instagram';
  else if (channel === 'LINKEDIN') queueTarget = 'publication-linkedin';
  else queueTarget = 'publication-facebook'; // fallback
}

return [{
  json: {
    is_adapted: resultStatus === 'ADAPTED',
    result_status: resultStatus,
    job_id: jobId,
    correlation_id,
    channel_name: channel,
    queue_target: queueTarget,
    error_code: p.error_code || null,
    error_message: p.error_message || null,
  }
}];

// Réponse finale — job adapté et enqueued pour publication
const data = $('Analyser résultat Adaptation').first().json;

return [{
  json: {
    worker: 'AdaptationWorker',
    status: 'completed',
    job_id: data.job_id,
    correlation_id: data.correlation_id,
    result_status: data.result_status,
    enqueued_to: data.queue_target,
    timestamp: new Date().toISOString(),
  }
}];

// Réponse — adaptation échouée
// BullMQ va réessayer automatiquement (backoff exponentiel)
const data = $input.first().json;

// Si c'est une erreur définitive (pas transient), ne pas retry
const permanentErrors = ['REJECTED_PAYLOAD', 'FAILED_ADAPTATION'];
const isPermanent = permanentErrors.includes(data.result_status);

if (isPermanent) {
  // Répondre OK pour que BullMQ ne retente pas
  return [{
    json: {
      worker: 'AdaptationWorker',
      status: 'completed_with_error',
      job_id: data.job_id,
      correlation_id: data.correlation_id,
      result_status: data.result_status,
      error_code: data.error_code,
      permanent_failure: true,
      message: 'Erreur définitive — pas de retry',
      timestamp: new Date().toISOString(),
    }
  }];
}

// Erreur transient (FAILED_LLM) → throw pour que BullMQ retry
throw new Error(`Adaptation failed (transient): ${data.result_status} — ${data.error_message}`);
